class Solution {
public:
    int minimumScore(string s, string t) {
        int n = s.size(), m = t.size();
        vector<int> next(n + 1, n);
        int j = m - 1;
        for (int i = n - 1; i >= 0; --i) {
            if (j >= 0 && s[i] == t[j]) --j;
            next[i] = j;
        }

        j = 0;
        int res = n;
        for (int i = 0; i < n; ++i) {
            if (j < m && s[i] == t[j]) ++j;
            if (j < m) {
                res = min(res, next[i + 1] - j + 1);
            }
        }
        return res;
    }
};
```
